def perceive(data):
    out = {}
    for line in str(data).splitlines():
        if ':' in line:
            k, v = line.split(':', 1)
            k = k.strip().lower()
            v = v.strip().replace(',', '').replace('$', '')
            if 'bank' in k or 'statement' in k:
                try:
                    out['bank_statement_balance'] = round(float(v), 2)
                except (ValueError, TypeError):
                    pass
    return out
